function solve(param) {
  const freq = {};
  for (const n of param) {
    freq[n] = (freq[n] || 0) + 1;
  }
  return param.sort((a, b) => {
    if (freq[a] !== freq[b]) return freq[a] - freq[b];
    return b - a;
  });
}

